export function toErrorMessage(t){if(t instanceof Error)return t.message;if(typeof t=="string")return t;try{return JSON.stringify(t)}catch{return String(t)}}function r(t,e){return{temperature:e?.temperature,maxTokens:e?.maxTokens,onStreamProgress:t.onStreamProgress,signal:e?.signal,timeoutMs:e?.timeoutMs}}export function createAgentRuntime(t){return{ctx:t,chat:(n,a)=>t.client.chat(t.model,n,r(t,a)),chatWithModel:(n,a,i)=>t.client.chat(n,a,r(t,i))}}
